import { createContext } from 'react';
import PROFILE from '../mock/profile';

const nameDetail = PROFILE.details.find((item) => item.label === 'Name');
const roleDetail = PROFILE.details.find((item) => item.label === 'Role');

const defaultUser = {
  name: nameDetail ? nameDetail.value : 'React Student',
  role: roleDetail ? roleDetail.value : 'Front-End Learner',
};

const UserContext = createContext(defaultUser);

export default UserContext;
